// // This module implements a master-slave D-latch with inverted outputs. Data is captured on the falling edge of the clock, and outputs are updated on the rising edge.
module master_slave_d_latch(  
    input D,  
    input CLK,  
    output reg Q,  
    output reg Qn  
);  
    reg master;  
    always @(posedge CLK) begin  
        master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= master;  
        Qn <= ~master;  
    end  
endmodule
